import{_ as a,o as i,c as s,ae as n}from"./chunks/framework.D7zHIyZF.js";const u=JSON.parse('{"title":"Configuration","description":"","frontmatter":{"title":"Configuration"},"headers":[],"relativePath":"configuration.md","filePath":"configuration.md"}'),t={name:"configuration.md"};function o(l,e,d,c,p,h){return i(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h1><p>jai uses line-based configuration files that live in <code>$HOME/.jai/</code> (or <code>$JAI_CONFIG_DIR</code> if set).</p><h2 id="config-file-lookup" tabindex="-1">Config file lookup <a class="header-anchor" href="#config-file-lookup" aria-label="Permalink to &quot;Config file lookup&quot;">​</a></h2><p>When you run <code>jai cmd</code>, jai looks for a configuration file in this order:</p><ol><li><strong><code>$HOME/.jai/cmd.conf</code></strong> — if <code>cmd</code> contains no slashes and does not start with <code>.</code></li><li><strong><code>$HOME/.jai/default.conf</code></strong> — fallback</li></ol><p>You can override this with <code>-C file</code> or <code>--conf file</code>. If the path contains no <code>/</code>, it is relative to <code>$HOME/.jai/</code>.</p><p>The command-line arguments and the configuration file can specify a <em>jail</em> by name. Otherwise, the jail name will be <code>default</code>. After the <code>.conf</code> file is parsed, jai will parse the <em>jail</em><code>.jail</code> file, which usually just specifies the mode of the jail, but can override other options set by the <code>.conf</code> file (other than the jail name itself). Command-line arguments override both the <code>.conf</code> and <code>.jail</code> files.</p><h2 id="syntax" tabindex="-1">Syntax <a class="header-anchor" href="#syntax" aria-label="Permalink to &quot;Syntax&quot;">​</a></h2><p>Each line has the form:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>option [value]</span></span></code></pre></div><p><code>option</code> is any long command-line option without the leading <code>--</code>. For example:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>conf .defaults</span></span>
<span class="line"><span>mode casual</span></span>
<span class="line"><span>dir /local/build</span></span>
<span class="line"><span>mask Mail</span></span></code></pre></div><p>Blank lines and comments (lines beginning with <code>#</code>) are ignored.</p><h2 id="the-conf-directive" tabindex="-1">The <code>conf</code> directive <a class="header-anchor" href="#the-conf-directive" aria-label="Permalink to &quot;The \`conf\` directive&quot;">​</a></h2><p><code>conf</code> acts as an include directive. It logically replaces the <code>conf</code> line with the contents of the specified file at that exact point. Relative paths are relative to <code>$HOME/.jai/</code>.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>conf .defaults</span></span>
<span class="line"><span>mode strict</span></span>
<span class="line"><span>dir /extra/path</span></span></code></pre></div><p>This reads <code>.defaults</code> first, then the subsequent lines override anything set in <code>.defaults</code>. Because <code>conf</code> is processed inline (not at the end), the order matters: later lines override earlier ones.</p><h2 id="the-defaults-file" tabindex="-1">The <code>.defaults</code> file <a class="header-anchor" href="#the-defaults-file" aria-label="Permalink to &quot;The \`.defaults\` file&quot;">​</a></h2><p>jai auto-generates a <code>.defaults</code> file with sensible defaults — blacklists for sensitive dotfiles (<code>.ssh</code>, <code>.gnupg</code>, etc.) and environment variables (tokens, keys, passwords). You should begin most configuration files with:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>conf .defaults</span></span></code></pre></div><p>If you changed your file and want to see the original version, you can print the default contents of the file with:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jai</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --print-defaults</span></span></code></pre></div><h2 id="the-command-directive" tabindex="-1">The <code>command</code> directive <a class="header-anchor" href="#the-command-directive" aria-label="Permalink to &quot;The \`command\` directive&quot;">​</a></h2><p>jai executes jailed programs through bash. The <code>command</code> directive lets you wrap or modify command execution. The default in <code>.defaults</code> is:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>command source &quot;\${JAI_SCRIPT:-/dev/null}&quot;; &quot;$0&quot; &quot;$@&quot;</span></span></code></pre></div><p>This sources any script files specified with <code>--script</code>, then runs the command (<code>$0</code>) with its arguments (<code>$@</code>). You can use <code>command</code> to set environment variables, activate virtual environments, or add flags.</p><h3 id="example-python-virtualenv" tabindex="-1">Example: Python virtualenv <a class="header-anchor" href="#example-python-virtualenv" aria-label="Permalink to &quot;Example: Python virtualenv&quot;">​</a></h3><p>Create <code>$HOME/.jai/python.conf</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>conf .defaults</span></span>
<span class="line"><span>mode strict</span></span>
<span class="line"><span>dir venv</span></span>
<span class="line"><span>jail python</span></span>
<span class="line"><span>command source $HOME/venv/bin/activate; &quot;$0&quot; &quot;$@&quot;</span></span></code></pre></div><p>Running <code>jai python</code> will now activate the virtualenv before executing the command.</p><h2 id="the-initjail-directive" tabindex="-1">The <code>initjail</code> directive <a class="header-anchor" href="#the-initjail-directive" aria-label="Permalink to &quot;The \`initjail\` directive&quot;">​</a></h2><p><code>initjail</code> runs a helper program when jai creates a jail home directory for the first time. This is most useful for strict and bare mode jails, where the home directory starts empty.</p><p>Important properties:</p><ul><li>The helper runs <strong>outside</strong> the jail, but with its current working directory set to the new jail home.</li><li>It runs with the invoking user&#39;s <strong>real uid/gid</strong>, not as root and not as the unprivileged <code>jai</code> user.</li><li>In configuration files, the program path is resolved relative to <code>$JAI_CONFIG_DIR</code> (usually <code>$HOME/.jai</code>).</li><li>jai sets <code>JAI_MODE</code>, <code>JAI_JAIL</code>, and <code>JAI_CONFIG_DIR</code> in the helper&#39;s environment.</li></ul><p>The helper runs once when jai creates the jail home for the first time. In strict and bare mode, that means when jai first creates the <code>&lt;name&gt;.home</code> directory. In casual mode, that means when jai first creates the overlay state for the jail, not when it later remounts an existing <code>.changes</code> directory.</p><p><code>initjail?</code> is the optional form. It behaves the same way, but is silently ignored if the program does not exist.</p><h3 id="example-seed-a-new-jail-from-a-skeleton-directory" tabindex="-1">Example: seed a new jail from a skeleton directory <a class="header-anchor" href="#example-seed-a-new-jail-from-a-skeleton-directory" aria-label="Permalink to &quot;Example: seed a new jail from a skeleton directory&quot;">​</a></h3><p>Create <code>$HOME/.jai/.initjail</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#!/bin/sh</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -eu</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$JAI_MODE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> strict ] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">||</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$JAI_MODE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> bare ]; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">then</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  cp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$JAI_CONFIG_DIR</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.skel/.&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fi</span></span></code></pre></div><p>Then reference it from a config file:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>conf .defaults</span></span>
<span class="line"><span>jail claude</span></span>
<span class="line"><span>initjail .initjail</span></span></code></pre></div><p>Now the first time jai creates the <code>claude</code> home directory, it will copy in the contents of <code>$HOME/.jai/.skel/</code>.</p><h2 id="cli-precedence" tabindex="-1">CLI precedence <a class="header-anchor" href="#cli-precedence" aria-label="Permalink to &quot;CLI precedence&quot;">​</a></h2><p>Command-line options are parsed both <strong>before and after</strong> the configuration file. This means command-line arguments always take precedence over config file directives.</p><p>Within a configuration file, the <code>conf</code> directive reads the included file at the exact point of the directive — it overrides previous lines and is subject to being overridden by subsequent lines.</p><h2 id="example-full-config-file" tabindex="-1">Example: full config file <a class="header-anchor" href="#example-full-config-file" aria-label="Permalink to &quot;Example: full config file&quot;">​</a></h2><p>Here is an example <code>~/.jai/codex.conf</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>conf .defaults</span></span>
<span class="line"><span>mode strict</span></span>
<span class="line"><span>jail codex</span></span>
<span class="line"><span>dir agents</span></span>
<span class="line"><span>dir .codex</span></span>
<span class="line"><span>setenv PREFIX=\${HOME}/agents</span></span>
<span class="line"><span>setenv PATH=\${PREFIX}/bin:\${PATH}</span></span></code></pre></div><p>This:</p><ol><li>Loads sensible defaults (blacklists, etc.)</li><li>Ensures strict mode (the default unless the codex jail was previously created in casual mode)</li><li>Names the jail <code>codex</code></li><li>Grants access to <code>~/agents</code> and <code>~/.codex</code> inside the jail</li><li>Sets the PREFIX environment variable, where <code>npm</code> will install software, to <code>~/agents</code></li><li>Prepends <code>~/agents/bin</code> to PATH before running the any command in the jail</li></ol><p>Now you can install or upgrade codex by running:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jai</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -C</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> codex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> i</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @openai/codex</span></span></code></pre></div><p>And since <code>codex.conf</code> is the default for the codex command, you can invoke codex with:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jai</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> codex</span></span></code></pre></div>`,54)])])}const g=a(t,[["render",o]]);export{u as __pageData,g as default};
